import * as React from 'react';

import { Slot } from '@radix-ui/react-slot';
import { type VariantProps } from 'class-variance-authority';

import { IconProvider, LoadingIcon } from '../icons';
import { cn } from '../utils/cn';
import { solidButtonVariants, textButtonVariants } from './common/variants';

const variantConfigs = {
  solid: solidButtonVariants,
  text: textButtonVariants,
} as const;

// Map button sizes to icon sizes: apply via icon context (IconProvider)
const iconSizeMap = {
  sm: 'xs',
  md: 'sm',
  lg: 'md',
  icon: 'md',
} as const;

// Slightly larger than content icons so the spinner reads
// well against the button chrome at each size.
const loadingIconSizeMap = {
  sm: 'sm',
  md: 'md',
  lg: 'lg',
  icon: 'md',
} as const;

// Define the props interface based on the variant configs
type ButtonVariant = keyof typeof variantConfigs;
type SolidButtonProps = VariantProps<typeof solidButtonVariants>;
type TextButtonProps = VariantProps<typeof textButtonVariants>;

interface ButtonProps extends Omit<React.ComponentProps<'button'>, 'color'> {
  variant?: ButtonVariant;
  color?:
    | NonNullable<SolidButtonProps['color']>
    | NonNullable<TextButtonProps['color']>;
  size?:
    | NonNullable<SolidButtonProps['size']>
    | NonNullable<TextButtonProps['size']>;
  asChild?: boolean;
  loading?: boolean;
}

/**
 * Preserves the button's intrinsic width during loading by
 * keeping children in the DOM with transparent text/icon color.
 * Unlike `visibility: hidden`, `text-transparent` keeps content
 * in the accessibility tree so the button retains its
 * accessible name. The spinner overlays with `aria-hidden`.
 */
function LoadingContent({
  size,
  children,
}: {
  size: keyof typeof loadingIconSizeMap;
  children: React.ReactNode;
}) {
  return (
    <>
      <span className="contents text-transparent">{children}</span>
      <span
        aria-hidden="true"
        className="absolute inset-0 flex items-center justify-center"
      >
        <LoadingIcon size={loadingIconSizeMap[size]} className="animate-spin" />
      </span>
    </>
  );
}

/**
 * A button component!
 *
 */
function Button({
  className,
  color = 'default',
  variant = 'solid',
  size = 'md',
  asChild = false,
  loading = false,
  onClick,
  children,
  ...props
}: ButtonProps) {
  const Comp = asChild ? Slot : 'button';
  // Slot requires a single child element; the loading overlay
  // Fragment would break that contract, so ignore loading when
  // asChild is true.
  const isLoading = loading && !asChild;

  const variantConfig = variantConfigs[variant];

  return (
    <IconProvider value={{ size: iconSizeMap[size] }}>
      <Comp
        data-slot="button"
        className={cn(
          variantConfig({ color, size }),
          isLoading && 'pointer-events-none relative',
          className
        )}
        aria-disabled={isLoading || undefined}
        aria-busy={isLoading || undefined}
        onClick={isLoading ? undefined : onClick}
        {...props}
      >
        {isLoading ? (
          <LoadingContent size={size}>{children}</LoadingContent>
        ) : (
          children
        )}
      </Comp>
    </IconProvider>
  );
}

export { Button };
